{
  "grammar": [
    {
      "pattern": "Subject + Verb + Object + 了",
      "structure": ["Subject", "Verb", "Object", "了"],
      "explanation_en": "In short chat messages, the subject is often omitted, and '了' indicates a change of state or completion. This is very common in Taiwanese messaging.",
      "title": "Message Ellipsis with 了",
      "meaning": "Indicates a completed action or change in status in a concise message.",
      "when_to_use": ["When reporting a completed action in a chat", "When informing someone of a change (e.g., arrival, departure)"],
      "when_not_to_use": ["In formal writing or full sentences", "When the action is ongoing or habitual"],
      "pragmatic_notes": "In Taiwan, dropping the subject is natural in casual messaging. '了' adds a sense of immediacy or finality.",
      "word_order_notes": "Standard SOV order, but subject is often omitted. '了' always comes at the end of the sentence.",
      "english_contrast": "English requires a subject (e.g., 'I arrived'), while Chinese often omits it in messages.",
      "korean_contrast": "Korean uses '-었어요' for past tense, but subject omission is also common in casual chat.",
      "negative_examples": [
        {
          "text": "我到了嗎",
          "error": "Adding '嗎' turns it into a question, but the pattern is for statements."
        }
      ],
      "incorrect_examples": [
        {
          "text": "到了我",
          "error": "Word order is wrong; '了' must be at the end."
        }
      ],
      "transformation_drills": ["Change '我到了' to '到了' (omit subject)", "Change '我吃了' to '吃了'"],
      "production_drills": ["Send a message saying you have arrived", "Send a message saying you have eaten"],
      "common_error_patterns": ["Forgetting to add '了'", "Keeping the subject when it's clear from context"],
      "repair_feedback": {
        "word_order": "Put '了' at the end of the sentence.",
        "politeness": "This pattern is neutral; for polite messages, add '不好意思'.",
        "vocabulary": "Use today's words like '到了', '吃了', '走了'."
      }
    },
    {
      "pattern": "Subject + Verb + Object + 嗎？",
      "structure": ["Subject", "Verb", "Object", "嗎"],
      "explanation_en": "A short confirmation question using '嗎' at the end. In messaging, the subject is often dropped for brevity.",
      "title": "Short Confirmation with 嗎",
      "meaning": "Asks for a yes/no confirmation in a concise way.",
      "when_to_use": ["When confirming plans or facts in a chat", "When checking if someone has done something"],
      "when_not_to_use": ["When asking open-ended questions", "In very formal contexts"],
      "pragmatic_notes": "In Taiwan, this is the most common way to confirm in messages. Dropping the subject is natural.",
      "word_order_notes": "Standard SOV order, but subject is often omitted. '嗎' always ends the sentence.",
      "english_contrast": "English uses inversion (e.g., 'Did you eat?'), while Chinese just adds '嗎'.",
      "korean_contrast": "Korean uses '-어요?' for questions, but '嗎' is simpler and more direct.",
      "negative_examples": [
        {
          "text": "吃了嗎了",
          "error": "Double '了' is incorrect; use only one '了' or just '嗎'."
        }
      ],
      "incorrect_examples": [
        {
          "text": "嗎吃了",
          "error": "'嗎' must be at the end, not the beginning."
        }
      ],
      "transformation_drills": ["Change '你吃了嗎' to '吃了嗎' (omit subject)", "Change '你到了嗎' to '到了嗎'"],
      "production_drills": ["Ask if someone has eaten", "Ask if someone has arrived"],
      "common_error_patterns": ["Putting '嗎' in the middle", "Using '嗎' with '了' incorrectly"],
      "repair_feedback": {
        "word_order": "Place '嗎' at the very end.",
        "politeness": "For polite confirmation, add '不好意思' before the question.",
        "vocabulary": "Use today's words like '吃了', '到了', '走了'."
      }
    },
    {
      "pattern": "不好意思 + [message]",
      "structure": ["不好意思", "message"],
      "explanation_en": "Use '不好意思' at the beginning of a message to politely apologize or preface a request. It softens the tone in Taiwanese messaging.",
      "title": "Polite Message Opener with 不好意思",
      "meaning": "A polite way to start a message, often to apologize or make a request.",
      "when_to_use": ["When apologizing for a delay or mistake", "When making a request in a chat", "When interrupting someone"],
      "when_not_to_use": ["In very casual messages between close friends", "When no apology or politeness is needed"],
      "pragmatic_notes": "In Taiwan, '不好意思' is very common in messaging to show politeness. It can mean 'excuse me' or 'sorry'.",
      "word_order_notes": "'不好意思' always comes first, followed by the main message.",
      "english_contrast": "English uses 'Sorry' or 'Excuse me' at the beginning, similar to Chinese.",
      "korean_contrast": "Korean uses '죄송합니다' or '실례합니다' in similar contexts.",
      "negative_examples": [
        {
          "text": "不好意思嗎",
          "error": "Adding '嗎' after '不好意思' is incorrect; it's not a question."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我不好意思遲到",
          "error": "'不好意思' should be at the beginning, not after the subject."
        }
      ],
      "transformation_drills": ["Change '對不起' to '不好意思' in a message", "Add '不好意思' before '我遲到了'"],
      "production_drills": ["Send a message apologizing for being late", "Send a message asking for a favor politely"],
      "common_error_patterns": ["Using '不好意思' in the middle of a sentence", "Forgetting to use it when needed"],
      "repair_feedback": {
        "word_order": "Put '不好意思' at the start of the message.",
        "politeness": "This makes your message more polite in Taiwanese context.",
        "vocabulary": "Use today's words like '遲到', '取消', '改天'."
      }
    }
  ]
}
